1	/**
2	 * Per-note outline-mode state, persisted in the plugin data store (decision
3	 * log Q2.6: files stay clean — no frontmatter, no markers). Pure module: the
4	 * plugin injects persistence, so this is unit-testable without Obsidian.
5	 *
6	 * `MarkerVisibility` lives here (not decorations.ts, which imports `obsidian`
7	 * for `editorInfoField`) specifically so this module can stay pure — it's
8	 * really just a data type, not a decoration-rendering concern.
9	 */
10	
11	/**
12	 * Which nodes get a block marker at all (Experiment 5a follow-up: markers
13	 * read as "a crown on top of the guide line" for a branch, but add little
14	 * for a leaf — most leaf atom kinds already carry their own native visual
15	 * style, e.g. a code fence's background or a callout's colored bar).
16	 * - 'all' — every eligible kind's first line (status quo).
17	 * - 'with-children' — only nodes that actually have at least one child.
18	 *   Atom kinds are leaves by construction, so this always excludes them.
19	 * - 'headings-and-paragraphs' — only the two kinds that CAN ever have
20	 *   children in this tree model, regardless of whether a given instance
21	 *   currently does. Atoms never qualify (they can't have children at all);
22	 *   list items are already excluded from markers unconditionally.
23	 */
24	export type MarkerVisibility = 'all' | 'with-children' | 'headings-and-paragraphs';
25	export const DEFAULT_MARKER_VISIBILITY: MarkerVisibility = 'all';
26	
27	export interface PluginData {
28	  outlinePaths: string[];
29	  coexistenceWarned: boolean;
30	  debugCrossCheck: boolean;
31	  /** Experiment 5a leaf-visibility round (see docs/research/07-decoration-
32	   * experiments-plan.md) — a real, persisted, user-facing setting so it can
33	   * be tried against a real vault without a rebuild. */
34	  markerVisibility: MarkerVisibility;
35	}
36	
37	export const DEFAULT_DATA: PluginData = {
38	  outlinePaths: [],
39	  coexistenceWarned: false,
40	  debugCrossCheck: false,
41	  markerVisibility: DEFAULT_MARKER_VISIBILITY,
42	};
43	
44	export class OutlineModeRegistry {
45	  private paths = new Set<string>();
46	
47	  constructor(private readonly persist: (paths: string[]) => Promise<void>) {}
48	
49	  hydrate(paths: readonly string[]): void {
50	    this.paths = new Set(paths);
51	  }
52	
53	  isOutline(path: string): boolean {
54	    return this.paths.has(path);
55	  }
56	
57	  async toggle(path: string): Promise<boolean> {
58	    const on = !this.paths.has(path);
59	    if (on) this.paths.add(path);
60	    else this.paths.delete(path);
61	    await this.save();
62	    return on;
63	  }
64	
65	  async handleRename(oldPath: string, newPath: string): Promise<void> {
66	    if (!this.paths.has(oldPath)) return;
67	    this.paths.delete(oldPath);
68	    this.paths.add(newPath);
69	    await this.save();
70	  }
71	
72	  async handleDelete(path: string): Promise<void> {
73	    if (!this.paths.delete(path)) return;
74	    await this.save();
75	  }
76	
77	  snapshot(): string[] {
78	    return [...this.paths].sort();
79	  }
80	
81	  private save(): Promise<void> {
82	    return this.persist(this.snapshot());
83	  }
84	}
